<template>
  <div class="layout">
    <Layout>
      <Header :style="{width: '100%', background: '#fff'}">
        <Menu mode="horizontal" :active-name="page" @on-select="redirctUrl">
          <div class="layout-logo">TAS</div>
          <div class="layout-nav">
            <MenuItem name="">
              <Icon type="ios-navigate"></Icon>
              Dashboard
            </MenuItem>
            <MenuItem name="blocks">
              <Icon type="ios-keypad"></Icon>
              BlockView
            </MenuItem>
            <MenuItem name="cards">
              <Icon type="social-dropbox"></Icon>
              Tools
            </MenuItem>
            <!--<MenuItem name="4">-->
              <!--<Icon type="ios-paper"></Icon>-->
              <!--Item 4-->
            <!--</MenuItem>-->
          </div>
        </Menu>
      </Header>
      <Content :style="{minHeight: '650px'}">
        <router-view/>
      </Content>
      <Footer class="layout-footer-center">2018 &copy; TASchain.cn</Footer>
    </Layout>
  </div>
</template>

<script>
export default {
  name: 'App',
  data() {
    return {
      page: "blocks"
    }
  },
  methods: {
    redirctUrl(path){
      window.location = "/" + path
    }
  },
  created() {
    this.page=this.$route.path.replace("/", "");
    console.log(this.GLOBAL.HOST);
  },

}
</script>

<style>
  .layout{
    /*border: 1px solid #d7dde4;*/
    background: #f5f7f9;
    position: relative;
    /*border-radius: 4px;*/
    overflow: hidden;
  }
  .layout-logo{
    width: 100px;
    height: 30px;
    float: left;
    position: relative;
    /*top: 15px;*/
    left: 20px;
    font-size: 30px;
  }
  .layout-nav{
    width: 380px;
    margin: 0 auto;
    margin-right: 20px;
  }
  .layout-footer-center{
    text-align: center;
  }
  .ivu-menu-horizontal.ivu-menu-light:after {
    height: 0;
  }
</style>



