<template>
  <div>
    <Row id="blocks">
      <Col :offset="3" :span="18">
        <p>Block List:</p>
        <Table :data="blocks" :columns="tableColumns1" stripe></Table>
        <div style="margin: 10px 0;overflow: hidden">
          <div style="float: right;">
            <Page :total="total" :current="1" show-total show-sizer @on-change="changePage" @on-page-size-change="changeSize"></Page>
          </div>
        </div>
      </Col>
    </Row>
  </div>
</template>

<script>
  import expandRow from './table-expand.vue'
    export default {
        name: "BlockView",
      component:[expandRow],
      data () {
        return {
          blocks:[
          ],
          blockscp:[],
          total:0,
          pageCount: 10,
          tableColumns1: [
            {
              type: 'expand',
              width:20,
              render: (h, params) => {
                return h(expandRow, {
                  props: {
                    row: params.row
                  }
                })
              }
            },
            {
              title: 'Height',
              key: 'height',
              width: 80,
              sortType:"asc",
              align:"center"
            },
            {
              title: 'Hash',
              key: 'hash',
              width:250,
              align:"center"
            },
            {
              title: 'QN',
              key: 'queue_number',
              width:70,
              align:"center"
            },
            {
              title: 'CurTime',
              key: 'cur_time',
              width: 100,
              align:"center"
            },
            {
              title: 'Castor',
              key: 'castor',
              width: 250,
              align:"center"
            },
            {
              title: 'GroupId',
              key: 'group_id',
              align:"center"
            },
          ]
        }
      },
      mounted() {
        setInterval(this.getBh, 1000);
      },
      methods: {
        getBh() {
          let params = {
            "method": "GTAS_blockHeight",
            "params": [],
            "jsonrpc": "2.0",
            "id": "1"
          };
          this.$ajax({
            url: "/",
            method:"post",
            data: JSON.stringify(params)
          }).then(response => {
            let rdata = response.data;
            if (rdata.result !== undefined){
              if (this.total===0 && rdata.result.data !== 0) {
                this.total = rdata.result.data;
                this.changePage(1);
              } else {
                this.total = rdata.result.data;
              }
            }
          })
        },
        syncBlock(height) {
          let params = {
            "method": "GTAS_getBlock",
            "params": [height],
            "jsonrpc": "2.0",
            "id": "1"
          };
          this.$ajax({
            url: "/",
            method:"post",
            data: JSON.stringify(params)
          }).then(response => {
            let rdata = response.data;
            if (rdata.result !== undefined){
              this.blockscp.push(rdata.result.data)
            }
            console.log(this.blockscp.length);
            if (this.blockscp.length === this.pageCount || height === this.total) {
              this.blocks = this.blockscp;
            }
          })
        },
        changePage(num) {
          this.blockscp = [];
          let offset = this.pageCount*(num-1);
          for (let i=offset+1; i <= offset+this.pageCount; i++) {
            if (i > this.total) {
              break
            }
            this.syncBlock(i);
          }
        },
        changeSize(count) {
          this.pageCount = count;
        }
      }
    }
</script>

<style scoped>
#blocks{
  margin: 30px 0;
}
</style>



