<style scoped>
  .expand-row{
    margin-bottom: 16px;
  }
</style>
<template>
  <div>
    <Row class="expand-row">
      <Col span="16">
        <span class="expand-key">PreHash: </span>
        <span class="expand-value">{{ row.pre_hash }}</span>
      </Col>
      <Col span="8">
        <span class="expand-key">PreTime: </span>
        <span class="expand-value">{{ row.pre_time }}</span>
      </Col>
    </Row>
    <Row class="expand-row">
      <Col span="24">
        <span class="expand-key">Signature: </span>
        <span class="expand-value">{{ row.signature }}</span>
      </Col>
    </Row>
    <Row class="expand-row">
      <Col span="24">
        <span class="expand-key">Transactions: </span>
        <span class="expand-value" v-for="item in row.transactions"><a href="javascript:;" @click="getTransitionInfo(item)">{{ item  }}</a>, &nbsp;</span>
      </Col>
    </Row>
    <Modal
      v-model="modal1"
      title="title"
    >
      <p>Hash: {{ hash }}</p>
      <p>Source: {{ source }}</p>
      <p>Target: {{ target }}</p>
      <p>Value: {{ value }}</p>
    </Modal>
  </div>
</template>
<script>
  export default {
    props: {
      row: Object
    },
    data(){
      return {
        modal1:false,
        source: "",
        target:"",
        value:"",
        hash:""
      }
    },
    methods:{
      getTransitionInfo(hash){
        let params = {
          "method": "GTAS_getTransaction",
          "params": [hash],
          "jsonrpc": "2.0",
          "id": "1"
        };
        this.$ajax({
          url: "/",
          method:"post",
          data: JSON.stringify(params)
        }).then(response => {
          let rdata = response.data;
          if (rdata.result !== undefined){
            this.modal1 = true;
            this.hash = hash;
            this.source = rdata.result.data.source;
            this.target = rdata.result.data.target;
            this.value = rdata.result.data.value;
          } else {

          }
        })
      }
    }
  };
</script>



